contracts/BatchRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./RoleManager.sol";

contract BatchRegistry {
    enum BatchStatus {
        ACTIVE,
        RECALLED,
        EXPIRED,
        SUSPICIOUS
    }

    struct Batch {
        bytes32 batchId;
        string medicineName;
        address manufacturer;
        uint64 manufactureDate;
        uint64 expiryDate;
        uint256 totalQuantity;
        BatchStatus status;
        bool exists;
    }

    RoleManager public immutable roleManager;

    mapping(bytes32 => Batch) public batches;
    mapping(bytes32 => bytes32) public unitToBatch;

    event BatchRegistered(bytes32 indexed batchId, address indexed manufacturer, string medicineName, uint256 totalQuantity);
    event BatchStatusUpdated(bytes32 indexed batchId, BatchStatus indexed status);
    event UnitSerialized(bytes32 indexed unitId, bytes32 indexed batchId, uint32 serialNumber);

    modifier onlyManufacturer() {
        require(roleManager.getRole(msg.sender) == RoleManager.Role.MANUFACTURER, "Only manufacturer");
        _;
    }

    constructor(address roleManagerAddress) {
        require(roleManagerAddress != address(0), "Invalid role manager");
        roleManager = RoleManager(roleManagerAddress);
    }

    function registerBatch(
        bytes32 batchId,
        string calldata medicineName,
        uint64 manufactureDate,
        uint64 expiryDate,
        uint256 totalQuantity
    ) external onlyManufacturer {
        require(batchId != bytes32(0), "Invalid batch");
        require(!batches[batchId].exists, "Batch exists");
        require(bytes(medicineName).length > 0, "Name required");
        require(expiryDate > manufactureDate, "Invalid dates");
        require(totalQuantity > 0, "Invalid quantity");

        batches[batchId] = Batch({
            batchId: batchId,
            medicineName: medicineName,
            manufacturer: msg.sender,
            manufactureDate: manufactureDate,
            expiryDate: expiryDate,
            totalQuantity: totalQuantity,
            status: BatchStatus.ACTIVE,
            exists: true
        });

        emit BatchRegistered(batchId, msg.sender, medicineName, totalQuantity);
    }

    function setBatchStatus(bytes32 batchId, BatchStatus status) external {
        Batch storage batch = batches[batchId];
        require(batch.exists, "Unknown batch");
        require(
            msg.sender == batch.manufacturer || roleManager.getRole(msg.sender) == RoleManager.Role.ADMIN,
            "Not authorized"
        );
        batch.status = status;
        emit BatchStatusUpdated(batchId, status);
    }

    function serializeUnit(bytes32 batchId, bytes32 unitId, uint32 serialNumber) external onlyManufacturer {
        Batch storage batch = batches[batchId];
        require(batch.exists, "Unknown batch");
        require(batch.manufacturer == msg.sender, "Wrong manufacturer");
        require(unitId != bytes32(0), "Invalid unit");
        require(unitToBatch[unitId] == bytes32(0), "Unit exists");

        unitToBatch[unitId] = batchId;
        emit UnitSerialized(unitId, batchId, serialNumber);
    }

    function getBatchByUnit(bytes32 unitId) external view returns (bytes32) {
        return unitToBatch[unitId];
    }
}

contracts/RoleManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

contract RoleManager {
    enum Role {
        NONE,
        MANUFACTURER,
        DISTRIBUTOR,
        PHARMACY,
        ADMIN
    }

    mapping(address => Role) private roles;

    event RoleAssigned(address indexed account, Role indexed role, address indexed assignedBy);

    modifier onlyAdmin() {
        require(roles[msg.sender] == Role.ADMIN, "Only admin");
        _;
    }

    constructor(address initialAdmin) {
        require(initialAdmin != address(0), "Invalid admin");
        roles[initialAdmin] = Role.ADMIN;
        emit RoleAssigned(initialAdmin, Role.ADMIN, msg.sender);
    }

    function assignRole(address account, Role role) external onlyAdmin {
        require(account != address(0), "Invalid account");
        require(role != Role.NONE, "Invalid role");
        roles[account] = role;
        emit RoleAssigned(account, role, msg.sender);
    }

    function revokeRole(address account) external onlyAdmin {
        require(account != address(0), "Invalid account");
        roles[account] = Role.NONE;
        emit RoleAssigned(account, Role.NONE, msg.sender);
    }

    function getRole(address account) external view returns (Role) {
        return roles[account];
    }

    function hasRole(address account, Role role) external view returns (bool) {
        return roles[account] == role;
    }
}

contracts/SaleRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./RoleManager.sol";

contract SaleRegistry {
    struct SaleRecord {
        bytes32 unitId;
        address pharmacy;
        address buyer;
        uint64 timestamp;
        bytes pharmacySig;
        bytes buyerSig;
    }

    RoleManager public immutable roleManager;
    mapping(bytes32 => SaleRecord) public sales;

    event SaleFinalized(bytes32 indexed unitId, address indexed pharmacy, address indexed buyer, uint64 timestamp);

    constructor(address roleManagerAddress) {
        require(roleManagerAddress != address(0), "Invalid role manager");
        roleManager = RoleManager(roleManagerAddress);
    }

    function finalizeSale(
        bytes32 unitId,
        address buyer,
        bytes calldata pharmacySig,
        bytes calldata buyerSig
    ) external {
        require(roleManager.getRole(msg.sender) == RoleManager.Role.PHARMACY, "Only pharmacy");
        require(unitId != bytes32(0), "Invalid unit");
        require(buyer != address(0), "Invalid buyer");
        require(sales[unitId].timestamp == 0, "Already sold");
        require(pharmacySig.length > 0 && buyerSig.length > 0, "Dual signatures required");

        sales[unitId] = SaleRecord({
            unitId: unitId,
            pharmacy: msg.sender,
            buyer: buyer,
            timestamp: uint64(block.timestamp),
            pharmacySig: pharmacySig,
            buyerSig: buyerSig
        });

        emit SaleFinalized(unitId, msg.sender, buyer, uint64(block.timestamp));
    }
}

